def calculate(inputs: dict) -> dict:
    """
    Calculates the recommended daily food quantity for an adult cat based on its weight.
    """

    # Reference data tables from the Farmina packaging feeding guide
    WEIGHTS_KG_REF = [2.0, 2.5, 3.0, 3.5, 4.0, 4.5, 5.0, 5.5, 6.0, 6.5]
    MIN_GRAMS_REF = [22, 25, 28, 32, 35, 38, 40, 42, 45, 48]
    MAX_GRAMS_REF = [36, 42, 48, 52, 58, 62, 66, 70, 75, 80]
    MIN_CUPS_REF = [0.25, 0.25, 0.33, 0.33, 0.33, 0.33, 0.50, 0.50, 0.50, 0.50]
    MAX_CUPS_REF = [0.33, 0.50, 0.50, 0.50, 0.66, 0.66, 0.66, 0.75, 0.75, 0.75]

    def _interpolate(x, x_points, y_points):
        """Performs linear interpolation or extrapolation based on reference points."""
        # Case 1: Extrapolation for weights below the defined range [1.0, 2.0)
        if x < x_points[0]:
            x1, x2 = x_points[0], x_points[1]
            y1, y2 = y_points[0], y_points[1]
        # Case 2: Extrapolation for weights above the defined range (6.5, 10.0]
        elif x > x_points[-1]:
            x1, x2 = x_points[-2], x_points[-1]
            y1, y2 = y_points[-2], y_points[-1]
        # Case 3: Interpolation for weights within the defined range [2.0, 6.5]
        else:
            # Handle exact match for the last point, which the loop would miss
            if x == x_points[-1]:
                return float(y_points[-1])
            # Find the correct interval for interpolation
            for i in range(len(x_points) - 1):
                if x_points[i] <= x < x_points[i+1]:
                    x1, x2 = x_points[i], x_points[i+1]
                    y1, y2 = y_points[i], y_points[i+1]
                    break
            else:
                # This part should not be reached with valid logic
                return {'error': 'Internal calculation error: Could not find interpolation interval.'}

        # Linear interpolation/extrapolation formula
        # Avoid division by zero if two consecutive x-points are the same
        if (x2 - x1) == 0:
            return float(y1)

        y = y1 + (x - x1) * (y2 - y1) / (x2 - x1)
        return y

    try:
        weight = float(inputs['weight'])
        weight_unit = inputs['weight_unit']
    except (KeyError, TypeError, ValueError):
        return {'error': 'Invalid input format. Please provide a numeric weight and a weight unit.'}

    # Validate the selected weight unit
    if weight_unit not in ['kg', 'lb']:
        return {'error': "Invalid Input: Unit must be 'kg' or 'lb'"}

    # 1. Convert weight to kilograms if 'weight_unit' is 'lb'
    if weight_unit == 'lb':
        weight_kg = weight * 0.45359237
    else:
        weight_kg = weight

    # Validate the weight in kg against the allowed range [1.0, 10.0]
    if not (1.0 <= weight_kg <= 10.0):
        return {'error': 'Invalid Input: Weight must be between 1.0 and 10.0 kg'}

    # 3 & 4. Calculate all metrics using the interpolation/extrapolation helper
    min_grams = _interpolate(weight_kg, WEIGHTS_KG_REF, MIN_GRAMS_REF)
    max_grams = _interpolate(weight_kg, WEIGHTS_KG_REF, MAX_GRAMS_REF)
    min_cups = _interpolate(weight_kg, WEIGHTS_KG_REF, MIN_CUPS_REF)
    max_cups = _interpolate(weight_kg, WEIGHTS_KG_REF, MAX_CUPS_REF)

    # 5. Round final grams to 1 decimal place and cups to 2 decimal places
    results = {
        'min_grams': round(min_grams, 1),
        'max_grams': round(max_grams, 1),
        'min_cups': round(min_cups, 2),
        'max_cups': round(max_cups, 2)
    }

    return results

