def calculate(inputs: dict) -> dict:
    """
    Calculates the recommended daily food quantity (in grams and cups) for an adult cat based on its weight, utilizing the feeding guidelines from Farmina packaging with precise linear interpolation.
    """

    # 2. Define reference tables from packaging
    WEIGHTS_KG = [2.0, 2.5, 3.0, 3.5, 4.0, 4.5, 5.0, 5.5, 6.0, 6.5]
    MIN_GRAMS = [22, 25, 28, 32, 35, 38, 40, 42, 45, 48]
    MAX_GRAMS = [36, 42, 48, 52, 58, 62, 66, 70, 75, 80]
    MIN_CUPS = [0.25, 0.25, 0.33, 0.33, 0.33, 0.33, 0.50, 0.50, 0.50, 0.50]
    MAX_CUPS = [0.33, 0.50, 0.50, 0.50, 0.66, 0.66, 0.66, 0.75, 0.75, 0.75]
    LB_TO_KG = 0.45359237

    # --- Input Extraction and Validation ---
    weight = inputs.get('weight')
    weight_unit = inputs.get('weight_unit')

    if weight is None or weight_unit is None:
        return {'error': 'Missing required input: weight and weight_unit must be provided.'}

    try:
        weight_val = float(weight)
    except (ValueError, TypeError):
        return {'error': 'Invalid Input: Weight must be a number.'}

    if not isinstance(weight_unit, str) or weight_unit not in ['kg', 'lb']:
        return {'error': "Invalid Input: weight_unit must be either 'kg' or 'lb'."}

    # 1. Convert weight to kilograms if 'weight_unit' is 'lb'
    weight_kg = weight_val * LB_TO_KG if weight_unit == 'lb' else weight_val

    # Validate weight range post-conversion
    if not (1.0 <= weight_kg <= 10.0):
        return {'error': 'Invalid Input: Weight must be between 1.0 and 10.0 kg (or equivalent in lb).'}

    # --- Interpolation/Extrapolation Function ---
    def _interpolate(x_val, x_points, y_points):
        # 3. If input weight in kg is outside [2.0, 6.5], perform linear extrapolation
        if x_val < x_points[0]:
            x1, x2 = x_points[0], x_points[1]
            y1, y2 = y_points[0], y_points[1]
        elif x_val > x_points[-1]:
            x1, x2 = x_points[-2], x_points[-1]
            y1, y2 = y_points[-2], y_points[-1]
        # 4. If within [2.0, 6.5], find the bounding interval and apply standard linear interpolation
        else:
            for i in range(len(x_points) - 1):
                if x_points[i] <= x_val <= x_points[i+1]:
                    x1, x2 = x_points[i], x_points[i+1]
                    y1, y2 = y_points[i], y_points[i+1]
                    break
            else: # Exact match on the last point
                return float(y_points[-1])

        if x1 == x2: # Avoid division by zero
            return float(y1)

        # Linear interpolation/extrapolation formula
        return y1 + (x_val - x1) * (y2 - y1) / (x2 - x1)

    # --- Calculation ---
    min_grams = _interpolate(weight_kg, WEIGHTS_KG, MIN_GRAMS)
    max_grams = _interpolate(weight_kg, WEIGHTS_KG, MAX_GRAMS)
    min_cups = _interpolate(weight_kg, WEIGHTS_KG, MIN_CUPS)
    max_cups = _interpolate(weight_kg, WEIGHTS_KG, MAX_CUPS)

    # 5. Round final grams to 1 decimal place and cups to 2 decimal places
    return {
        'min_grams': round(min_grams, 1),
        'max_grams': round(max_grams, 1),
        'min_cups': round(min_cups, 2),
        'max_cups': round(max_cups, 2)
    }
